import{_ as e,o as i,c as t,a2 as a}from"./chunks/framework.B08aFN1B.js";const k=JSON.parse('{"title":"Slides & Present","description":"","frontmatter":{},"headers":[],"relativePath":"slides.md","filePath":"slides.md","lastUpdated":null}'),n={name:"slides.md"};function o(l,s,r,d,p,h){return i(),t("div",null,[...s[0]||(s[0]=[a(`<h1 id="Slides-and-Present" tabindex="-1">Slides &amp; Present <a class="header-anchor" href="#Slides-and-Present" aria-label="Permalink to &quot;Slides &amp; Present {#Slides-and-Present}&quot;">​</a></h1><p>Any notebook is also a <strong>slide deck</strong>. The same cells you edit group into slides by their headings — no separate authoring mode, no second copy of the content. Present them live in the browser, or export a typeset PDF deck.</p><h2 id="Present-mode-—-Present" tabindex="-1">Present mode — ▶ Present <a class="header-anchor" href="#Present-mode-—-Present" aria-label="Permalink to &quot;Present mode — ▶ Present {#Present-mode-—-Present}&quot;">​</a></h2><p>Click <strong>▶ Present</strong> in the top bar (or press <strong>⌘⇧P</strong>) to enter full-screen presentation. The notebook&#39;s cells are segmented into slides and shown one at a time; arrow keys advance. Press <code>Esc</code> to exit back to the editor.</p><p>Because the deck <em>is</em> the notebook, your figures, tables, and <code>@bind</code> controls are all live on the slide — a slider still drives its chart mid-presentation.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/present-slide.png" alt=""></p><h2 id="How-cells-become-slides" tabindex="-1">How cells become slides <a class="header-anchor" href="#How-cells-become-slides" aria-label="Permalink to &quot;How cells become slides {#How-cells-become-slides}&quot;">​</a></h2><p>Segmentation follows a small set of boundary rules (shared by Present mode and the PDF export, so both agree):</p><ol><li><p>A <strong>markdown heading</strong> at or above the slide level (default <code>##</code> / H2) starts a new slide.</p></li><li><p>A cell tagged <strong><code>slide</code></strong> forces a new slide, regardless of headings.</p></li><li><p>A <strong>thematic break</strong> (<code>---</code> on its own line) <em>inside</em> a markdown cell splits it mid-cell into separate slides.</p></li><li><p>A cell tagged <strong><code>notes</code></strong> attaches to the current slide as <strong>speaker notes</strong> (never shown in the slide body).</p></li><li><p>Cells before the first boundary form the leading <strong>title slide</strong>.</p></li><li><p><code>collapsed</code> cells are omitted (matching the article/report export).</p></li></ol><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=title</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reactive Notebooks</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">### a five-minute tour</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=idea</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## The core idea            ← starts slide 2 (H2 heading)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Change a value; only the downstream cells recompute.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% code id=demo slide      ← \`slide\` tag forces slide 3, even without a heading</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Slider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:line</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.(f </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">./</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=sp notes          ← speaker notes for slide 3, not shown on it</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Remember to drag the slider here.</span></span></code></pre></div><p>Set the <strong>slide level</strong> (how deep a heading has to be to start a slide — H1 only, through H3), the <strong>transition</strong>, the <strong>theme</strong>, and the <strong>aspect ratio</strong> (16:9 or 4:3) per notebook in <strong>☰ → 🎚 Notebook config</strong> (see <a href="/KaimonSlate.jl/dev/configuration#notebook-config">Configuration</a>). These pin to the notebook and travel in its <code>.jl</code>.</p><h2 id="Export-a-PDF-deck" tabindex="-1">Export a PDF deck <a class="header-anchor" href="#Export-a-PDF-deck" aria-label="Permalink to &quot;Export a PDF deck {#Export-a-PDF-deck}&quot;">​</a></h2><p><strong>☰ → ⬆ Export…</strong>, format <strong>PDF</strong>, layout <strong>🎞 Slides — presentation deck</strong>. This renders a typeset landscape deck <strong>server-side via Typst</strong> — one slide per page, 16:9 (or 4:3), auto-fit:</p><ul><li><p><strong>Code listings are hidden by default</strong> on slides (a deck shows results, not source); the <em>Code listings</em> option turns them back on.</p></li><li><p><strong>Vector figures</strong> — CairoMakie embeds as PDF, ECharts as SVG (light+dark captured), so a slide stays crisp on a projector.</p></li><li><p><strong>Speaker notes</strong> — tick <strong>Append speaker-notes pages to the deck</strong> to follow the deck with a notes appendix (one page per slide that has <code>notes</code> cells).</p></li></ul><p>The route is <code>GET /api/&lt;id&gt;/export.pdf?layout=slides</code> (<code>?theme=</code>, <code>?columns=</code> ignored for decks; <code>?code=</code> sizes/hides listings). See <a href="./export">Export</a> for the shared PDF options and the editable Typst project (<code>export.typ</code>).</p><div class="tip custom-block"><p class="custom-block-title">One source, three artifacts</p><p>The same notebook is a live document, a full-screen presentation, and a typeset PDF deck. Add a few <code>##</code> headings and it&#39;s already a deck — refine with <code>slide</code> / <code>notes</code> tags and the Notebook-config knobs.</p></div>`,16)])])}const g=e(n,[["render",o]]);export{k as __pageData,g as default};
